INSERT INTO `bot_aprendizaje` (`id`, `pregunta_hash`, `pregunta_normalizada`, `pregunta_original`, `respuesta`, `categoria`, `frecuencia`, `creado_en`, `ultimo_acceso`) VALUES ('147','a5fd5c8b29f9d91b01f6f75324961b01','cabl tien','hola tienes cables','Hola Jose, revisé y no encuentro *\"tienes cables\"* en nuestro catálogo actual. ¿Quizás lo conoces por otro nombre? También puedes ver todo nuestro inventario en la tienda online: http://localhost/proyecto/interfaz_usuario/pagina_modernizada.html\n\n¿Qué producto andas buscando?','general','1','2026-06-13 11:34:23','2026-06-13 11:34:23');
INSERT INTO `bot_aprendizaje` (`id`, `pregunta_hash`, `pregunta_normalizada`, `pregunta_original`, `respuesta`, `categoria`, `frecuencia`, `creado_en`, `ultimo_acceso`) VALUES ('149','0479273ef88b01a2626b8e47f914d478','das detall mas producto','me das mas detalles del producto','No encontré \"me das mas detalles del producto\" en mi catálogo, Jose. Probá con otro nombre, por ejemplo:\n• sensor, contactor, relé térmico\n• breaker, pulsador, guardamotor\n• variador, fuente, instrumento de medición\n\nO consultá nuestra tienda online: http://localhost/proyecto/interfaz_usuario/pagina_modernizada.html','general','1','2026-06-13 11:48:47','2026-06-13 11:48:47');
INSERT INTO `bot_aprendizaje` (`id`, `pregunta_hash`, `pregunta_normalizada`, `pregunta_original`, `respuesta`, `categoria`, `frecuencia`, `creado_en`, `ultimo_acceso`) VALUES ('151','9934bb6bcdea769d1608b3b9817fdbf3','des metodo pago','metodo des pago','*Métodos de Pago*\n\nAceptamos:\n\n🏦 *Transferencia Bancaria* — disponible 24/7\n📱 *Pago Móvil* — todos los bancos\n💵 *Efectivo* — retirando en tienda\n💲 *Dólares* — tasa BCV del día\n\nTodos los precios están en Bolívares (Bs.) y no incluyen IVA.\nAl pagar de contado aplican descuentos especiales.\n\n¿Qué producto te interesa? Te paso el precio exacto.','general','1','2026-06-13 11:51:00','2026-06-13 11:51:00');
