INSERT INTO `bot_aprendizaje` (`id`, `pregunta_hash`, `pregunta_normalizada`, `pregunta_original`, `respuesta`, `categoria`, `frecuencia`, `creado_en`, `ultimo_acceso`) VALUES ('273','38cd98785603a5e9c3131750bb574f63','envios hacen','hacen envios','*Información de Envíos*\n\nRealizamos envíos a todo Venezuela a través de:\n• MRW — 24 a 72 horas hábiles\n• Tealca — 24 a 72 horas hábiles\n• Zoom — 24 a 72 horas hábiles\n\nUna vez procesado tu pedido, te enviamos el número de guía para que puedas rastrear tu envío.\n\nSi tienes un pedido en curso y quieres saber si fue enviado, escríbenos con tu número de pedido o nombre completo y lo consultamos.','general','1','2026-06-13 12:17:14','2026-06-13 12:17:14');
