INSERT INTO `bot_aprendizaje` (`id`, `pregunta_hash`, `pregunta_normalizada`, `pregunta_original`, `respuesta`, `categoria`, `frecuencia`, `creado_en`, `ultimo_acceso`) VALUES ('285','b9e28c5332d7cf7d2a8d95324b708b2d','botonera cable colgante metodos necesito pago sensor son','hola buenas como esta necesito un cable para sensor m8 y una botonera colgante cuales son los metodos de pago','*Métodos de Pago*\n\nAceptamos:\n\n🏦 *Transferencia Bancaria* — disponible 24/7\n📱 *Pago Móvil* — Mercantil y Provincial\n💵 *Efectivo* — retirando en tienda\n💲 *Dólares* — tasa BCV del día\n\nTodos los precios están en Bolívares (Bs.) y no incluyen IVA.\nAl pagar de contado aplican descuentos especiales.\n\n*Productos relacionados:*\n*Cable para sensor M8*\n📂 Accesorios\n💰 Precio: *Bs. 55,00*\n📦 Stock: 90 unidades\n📝 Marca Telemecanique Modelo Xzcp0941l2.\n\n*Botonera colgante*\n📂 Botoneras\n💰 Precio: *Bs. 180,00*\n📦 Stock: 25 unidades\n📝 Botonera colgante de 6 pulsadores Marca schneider electric modelo xaca671 material propipolineno.\n\n\n\n🔗 http://localhost/proyecto/interfaz_usuario/pagina_modernizada.html','general','1','2026-06-13 12:22:22','2026-06-13 12:22:22');
