INSERT INTO `bot_aprendizaje` (`id`, `pregunta_hash`, `pregunta_normalizada`, `pregunta_original`, `respuesta`, `categoria`, `frecuencia`, `creado_en`, `ultimo_acceso`) VALUES ('290','1626f1dcc8c19431ec186b4b94d10a8c','envíos hacen','hacen envíos','*Información de Envíos*\n\nRealizamos envíos a todo Venezuela a través de:\n• MRW — 24 a 72 horas hábiles\n• Tealca — 24 a 72 horas hábiles\n• Zoom — 24 a 72 horas hábiles\n\nUna vez procesado tu pedido, te enviamos el número de guía para que puedas rastrear tu envío.\n\nSi tienes un pedido en curso y quieres saber si fue enviado, escríbenos con tu número de pedido o nombre completo y lo consultamos.','general','3','2026-06-15 08:35:41','2026-06-15 08:36:41');
