INSERT INTO `bot_aprendizaje` (`id`, `pregunta_hash`, `pregunta_normalizada`, `pregunta_original`, `respuesta`, `categoria`, `frecuencia`, `creado_en`, `ultimo_acceso`) VALUES ('292','a44487f61735dc68a3928423ffc4581a','comprar cómo','cómo comprar','¡Claro Test! Puedes comprar nuestros productos de dos formas:\n\n1️⃣ *Tienda Online* — visita nuestro catálogo y compra en línea:\nhttp://localhost/proyecto/interfaz_usuario/pagina_modernizada.html\n\n2️⃣ *Contactando a un asesor* — escríbenos por WhatsApp o llámanos:\n📞 +58 0424-8323902\n📧 Picca.ventas@gmail.com\n\n¿Qué producto te interesa? ¡Dime el nombre y te paso precio y disponibilidad!','general','3','2026-06-15 08:35:41','2026-06-15 08:36:41');
