  PRIMARY KEY (`id`),
  UNIQUE KEY `sku` (`sku`),
  FULLTEXT KEY `idx_products_fulltext` (`name`,`description`)
) ENGINE=InnoDB AUTO_INCREMENT=88 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

